/**
 * RetryPolicy
 *
 * Domain rule for retry/terminal decisions.
 *
 * Owns the *decision* (should we retry? how long to back off?); the adapter
 * owns the *mechanism* (actually sleeping, re-invoking). Persisted per-plan so
 * it is configurable and survives crashes. This is also what makes
 * "retries exhausted -> terminal FAILED" a domain rule rather than adapter magic.
 */
export type RetryPolicy = {
    /**
     * Max Attempts
     */
    max_attempts?: number;
    /**
     * Initial Backoff Seconds
     */
    initial_backoff_seconds?: number;
    /**
     * Backoff Multiplier
     */
    backoff_multiplier?: number;
    /**
     * Max Backoff Seconds
     */
    max_backoff_seconds?: number;
    /**
     * Jitter Ratio
     */
    jitter_ratio?: number;
    /**
     * Kind Max Attempts
     */
    kind_max_attempts?: {
        [key in FailureKind]?: number;
    };
    /**
     * Kind Backoff Scale
     */
    kind_backoff_scale?: {
        [key in FailureKind]?: number;
    };
    /**
     * Non Retryable Kinds
     */
    non_retryable_kinds?: Array<FailureKind>;
};

/**
 * RetryPolicyUpdateRequest
 *
 * All fields optional: only the ones an operator sets are changed (partial
 * merge over the plan's current retry policy); the rest keep their current
 * value. Mirrors execution.retry_* config field-for-field.
 */
export type RetryPolicyUpdateRequest = {
    /**
     * Max Attempts
     */
    max_attempts?: number | null;
    /**
     * Initial Backoff Seconds
     */
    initial_backoff_seconds?: number | null;
    /**
     * Backoff Multiplier
     */
    backoff_multiplier?: number | null;
    /**
     * Max Backoff Seconds
     */
    max_backoff_seconds?: number | null;
    /**
     * Jitter Ratio
     */
    jitter_ratio?: number | null;
};

